DDL:
DROP TABLE IF EXISTS DIM_COUNTRY CASCADE;
CREATE TABLE DIM_COUNTRY (
	COUNTRY_ID BIGINT PRIMARY KEY,
	COUNTRY_NAME VARCHAR(20)
);

DROP TABLE IF EXISTS DIM_DISTRICT CASCADE;
CREATE TABLE DIM_DISTRICT (
	DISTRICT_ID BIGINT PRIMARY KEY,
	DISTRICT_NAME VARCHAR(50)
);

DROP TABLE IF EXISTS DIM_STATE CASCADE;
CREATE TABLE DIM_STATE (
	STATE_ID BIGINT PRIMARY KEY,
	STATE_NAME VARCHAR(100)
);

DROP TABLE IF EXISTS DIM_SUB_DISTRICT CASCADE;
CREATE TABLE DIM_SUB_DISTRICT (
	SUB_DISTRICT_ID BIGINT PRIMARY KEY,
	SUB_DISTRICT_NAME VARCHAR(100)
);

DROP TABLE IF EXISTS FACT_COMMUNICATIONS CASCADE;
CREATE TABLE FACT_COMMUNICATIONS (
	SUB_DISTRICT_ID BIGINT PRIMARY KEY,
	NUMBER_OF_POST_OFFICES DOUBLE PRECISION,
	NUMBER_OF_TELEGRAPH_OFFICES DOUBLE PRECISION,
	NUMBER_OF_POST_AND_TELEGRAPH_OFFICES DOUBLE PRECISION,
	NUMBER_OF_TELEPHONE_CONNECTIONS DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_FINANCIAL_SERVICES CASCADE;
CREATE TABLE FACT_FINANCIAL_SERVICES (
	SUB_DISTRICT_ID BIGINT PRIMARY KEY,
	NUMBER_OF_COMMERCIAL_BANKS DOUBLE PRECISION,
	NUMBER_OF_CO_OPERATIVE_COMMERCIAL_BANKS DOUBLE PRECISION,
	NUMBER_OF_AGRICULTURAL_CREDIT_SOCIETIES DOUBLE PRECISION,
	NUMBER_OF_NON_AGRICULTURAL_CREDIT_SOCIETIES DOUBLE PRECISION,
	NUMBER_OF_OTHER_CREDIT_SOCIETIES DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_MEDICAL_PERSONNEL CASCADE;
CREATE TABLE FACT_MEDICAL_PERSONNEL (
	SUB_DISTRICT_ID BIGINT PRIMARY KEY,
	NUMBER_OF_REGISTERED_PRIVATE_MEDICAL_PRACTITIONERS DOUBLE PRECISION,
	NUMBER_OF_SUBSIDED_MEDICAL_PRACTITIONERS DOUBLE PRECISION,
	NUMBER_OF_COMMUNITY_HEALTH_WORKERS DOUBLE PRECISION
);

DROP TABLE IF EXISTS FACT_RECREATION_SPORTS CASCADE;
CREATE TABLE FACT_RECREATION_SPORTS (
	SUB_DISTRICT_ID BIGINT PRIMARY KEY,
	NUMBER_OF_CINEMA_VIDEO_HALLS DOUBLE PRECISION,
	NUMBER_OF_SPORTS_CLUBS DOUBLE PRECISION,
	NUMBER_OF_STADIUMS_OR_AUDITORIUMS DOUBLE PRECISION
);
